const body = $json.body || $json;
const url = (body.url || '').trim();

if (!url || !url.startsWith('http')) {
  throw new Error('Invalid input: must provide a valid job URL in body.url');
}

// Parse company/domain from URL
let domain = '';
let company = body.company || '';
try {
  const parsed = new URL(url);
  domain = parsed.hostname.replace('www.', '');
  if (!company) company = domain.split('.')[0];
} catch(e) { throw new Error('Invalid URL: ' + url); }

// Determine source from domain
const sourceMap = {
  'greenhouse.io': 'Greenhouse', 'lever.co': 'Lever', 'ashbyhq.com': 'Ashby',
  'wellfound.com': 'Wellfound', 'myworkdayjobs.com': 'Workday', 'linkedin.com': 'LinkedIn',
  'smartrecruiters.com': 'SmartRecruiters', 'icims.com': 'iCIMS'
};
const source = Object.entries(sourceMap).find(([d]) => domain.includes(d))?.[1] || 'Manual';

// Generate ID
const dateStr = new Date().toISOString().slice(0, 10).replace(/-/g, '');
const rand = Math.random().toString(36).substring(2, 6);
const id = `${source.toLowerCase().replace(/\s/g, '_')}_${dateStr}_${rand}`;

const title = (body.title || '').trim();
const company_clean = (body.company || company).trim();

return [{
  json: {
    id,
    source,
    company: company_clean,
    title,
    url,
    domain,
    dedupKey: `${company_clean.toLowerCase()}|${title.toLowerCase()}|${domain}`,
    dateFound: new Date().toISOString(),
    status: 'New'
  }
}];

const sourceItem = $('Validate & Normalize Input').first();
const htmlResponse = $input.first().json;
let jdText = '';
let confidence = 'high';

if (htmlResponse.error || !htmlResponse) {
  jdText = sourceItem.json.title + ' at ' + sourceItem.json.company;
  confidence = 'low';
} else {
  const html = typeof htmlResponse === 'string' ? htmlResponse : JSON.stringify(htmlResponse);
  jdText = html
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&nbsp;/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .substring(0, 8000);

  if (jdText.length < 200) {
    jdText = sourceItem.json.title + ' at ' + sourceItem.json.company;
    confidence = 'low';
  }
}

return [{ json: { ...sourceItem.json, jdText, confidence } }];

const raw = $input.first().json.output || $input.first().json.text || '{}';
const sourceItem = $('Extract JD Text').first();
let eval_data = {};

try {
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) eval_data = JSON.parse(match[0]);
} catch(e) {
  eval_data = { scores: {}, overall: 0, grade: 'F', summary: 'Parse error', confidence: 'low' };
}

const scores = eval_data.scores || {};
const weights = { role_match: 0.20, skills: 0.20, seniority: 0.12, compensation: 0.10, geographic: 0.08, company_stage: 0.08, product_market: 0.07, growth: 0.07, interview_likelihood: 0.05, timeline: 0.03 };
const weightedScore = Object.keys(weights).reduce((sum, k) => sum + (scores[k] || 3) * weights[k], 0);

let finalScore = weightedScore;
let finalGrade = eval_data.grade || 'C';
if ((scores.role_match || 0) <= 1 || (scores.skills || 0) <= 1) {
  finalGrade = 'D'; finalScore = Math.min(finalScore, 2.9);
}

return [{ json: { ...sourceItem.json, eval: eval_data, scores, overall: parseFloat(weightedScore.toFixed(2)), grade: finalGrade, status: 'Evaluated' } }];

const raw = $input.first().json.output || '{}';
const sourceItem = $('Apply Scoring').first();
let cvData = {};
try { const m = raw.match(/\{[\s\S]*\}/); if(m) cvData = JSON.parse(m[0]); } catch(e) {}

const expHtml = (cvData.experience || []).map(r => `<div><strong>${r.company}</strong> — ${r.role} <span>${r.dates}</span><ul>${(r.bullets||[]).map(b=>`<li>${b}</li>`).join('')}</ul></div>`).join('');
const skills = cvData.skills || {};
const skillsText = [skills.design?.join(', '), skills.technical?.join(', '), skills.tools?.join(', ')].filter(Boolean).join(' | ');
const c = cvData.contact || {};
const cvHtml = `<html><body style='font-family:sans-serif;max-width:800px;margin:0 auto;padding:40px;'><h1>${c.name||'Preston Bezant'}</h1><p>${cvData.title||''}</p><p>${c.email||''} | ${c.phone||''} | ${c.portfolio||''} | ${c.location||''}</p><h2>Summary</h2><p>${cvData.summary||''}</p><h2>Experience</h2>${expHtml}<h2>Skills</h2><p>${skillsText}</p></body></html>`;

return [{ json: { ...sourceItem.json, cvData, cvHtml } }];

